import sailpoint.object.Capability;
import sailpoint.object.Identity;
import sailpoint.object.Identity.CapabilityManager;
import sailpoint.object.QueryOptions;
import sailpoint.object.Bundle;
import sailpoint.object.Filter;
import sailpoint.object.ObjectAttribute;
import sailpoint.object.ObjectConfig;

import sailpoint.api.ObjectUtil;

import sailpoint.object.RoleTypeDefinition;

import sailpoint.tools.Util;

String newLine = System.lineSeparator();


//String loggedInUser = "spadmin";
//List roleIds = null;



public void log(String message) {    
  log.error(logPrefix+" "+message);
}






List typeList = Util.csvToList("it,business");


ObjectConfig objConfig = context.getObjectByName(ObjectConfig.class, "Bundle");
RoleTypeDefinition itDef = objConfig.getRoleType("it");
RoleTypeDefinition buzDef = objConfig.getRoleType("business");

List itDisAllowedAttributes = itDef.getDisallowedAttributes();
List buzDisAllowedAttributes = buzDef.getDisallowedAttributes();	


List objectAttributes = objConfig.getObjectAttributes();

//List extendedAttributes = objConfig.getExtendedAttributeList();
String header = "Role Name,DisplayName,Type,Owner,Description,Disabled";
StringBuilder sb = new StringBuilder();



//IT Roles line

StringBuilder itRoleSb = new StringBuilder();
StringBuilder buzRoleSb = new StringBuilder();

for(ObjectAttribute objAttr : Util.safeIterable(objectAttributes)) {

  if (!Util.nullSafeContains(itDisAllowedAttributes,objAttr.getName())) {
    itRoleSb.append(","+objAttr.getName());
  }

  if (!Util.nullSafeContains(buzDisAllowedAttributes,objAttr.getName())) {
    buzRoleSb.append(","+objAttr.getName());
  }

}

itRoleSb.append(",AddEntitlement,RemoveEntitlement");
buzRoleSb.append(",AddITRoles,RemoveITRoles");





StringBuilder defSb = new StringBuilder();
defSb.append("Attribute Name,Type,Required,Allowed Values");


for(ObjectAttribute objAttr : Util.safeIterable(objectAttributes)) {
  defSb.append(newLine);
  defSb.append(objAttr.getName());
  defSb.append(",");
  if (objAttr.getType() == null) {
    defSb.append("string");
  }
  else {
    defSb.append(objAttr.getType());
  }

  defSb.append(",");
  defSb.append(objAttr.isRequired());
  defSb.append(",");

  if ("boolean".equals(objAttr.getType())) {
    defSb.append("TRUE/FALSE");
  }
  else {
    List allowedValues = objAttr.getAllowedValues();
    if (allowedValues != null && !allowedValues.isEmpty()) {
      for(String value : allowedValues) {
        defSb.append(value);
        defSb.append(newLine);
        defSb.append(",,,");
      }
    }
  }





}


//return defSb.toString();
sb.append("IT Role Upadte Header"+newLine);

sb.append(header+itRoleSb.toString());
sb.append(newLine+newLine);

sb.append("Business Role Update Header"+newLine);
sb.append(header+buzRoleSb.toString());
sb.append(newLine+newLine);

sb.append("Attributes Definitions and Allowed Values"+newLine);
sb.append(defSb.toString());







return sb.toString();
